<template>
  <div>
    <HeroHeaderDashboard :title="title" :breadcrumbs="breadcrumbs">
      <template #actions>
        <NuxtLink
          class="btn btn--primary"
          :to="`/dashboard/maintenance/conditions/${route.params.id}/edit`"
        >
          Editar condición
        </NuxtLink>
      </template>
    </HeroHeaderDashboard>
    <BoxContent>
      <template #content>
        <BoxInformation title="Información" :columns="2">
          <CardInfoDashboard
            v-if="item"
            title="Nombre"
            :description="item.name"
          />
          <CardInfoDashboard
            v-if="item"
            title="Slug"
            :description="item.slug"
          />
        </BoxInformation>
      </template>
      <template #sidebar>
        <BoxInformation title="Detalles" :columns="1">
          <CardInfoDashboard
            v-if="item"
            title="Fecha de creación"
            :description="formatDate(item.createdAt)"
          />
          <CardInfoDashboard
            v-if="item"
            title="Última modificación"
            :description="formatDate(item.updatedAt)"
          />
        </BoxInformation>
      </template>
    </BoxContent>
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from "vue";
import { useRoute } from "vue-router";
import type { ConditionData } from "@/components/FormCondition.vue";
import { formatDate } from "@/utils/date";

interface ConditionRecord extends ConditionData {
  slug?: string;
  createdAt?: string;
  updatedAt?: string;
}

definePageMeta({
  layout: "dashboard",
});

const route = useRoute();
const item = ref<ConditionRecord | null>(null);
const apiClient = useApiClient();

const title = computed(() => item.value?.name || "Condición");
const breadcrumbs = computed(() => [
  { label: "Condiciones", to: "/dashboard/maintenance/conditions" },
  ...(item.value?.name ? [{ label: item.value.name }] : []),
]);

const { data: conditionData } = await useAsyncData(
  `condition-${route.params.id}`,
  async () => {
    const id = route.params.id;
    if (!id) return null;

    const response = (await apiClient("conditions", {
      method: "GET",
      params: { filters: { documentId: { $eq: id } } } as unknown as Record<
        string,
        unknown
      >,
    })) as { data: unknown[] };
    const data = Array.isArray(response.data) ? response.data[0] : null;
    if (data) return data;

    const fallback = (await apiClient(`conditions/${id}`, {
      method: "GET",
    })) as { data: unknown };
    return (fallback.data as unknown) || null;
  },
);

item.value = conditionData.value ?? null;
</script>
